namespace TranSmart.Service.Organization
{
    public partial interface IEmployeeService : IBaseService<Employee>
    {

    }

    public partial class EmployeeService : BaseService<Employee>, IEmployeeService
    {
        public EmployeeService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Employee item, Result<Employee> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Employee>().HasRecordsAsync(x => x.No == item.No  && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Employee.No), "No already exists"));
            }
        }
        public override async Task<Employee> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Employee>().SingleAsync(
                predicate: x => x.ID == id,
                include: i => i.Include(x => x.Department).Include(x => x.Designation).Include(x => x.WorkLocation).Include(x => x.WorkType).Include(x => x.Team).Include(x => x.ReportingTo).Include(x => x.EmpCategory).Include(x => x.ProbationPeriod).Include(x => x.LOB).Include(x => x.FunctionalArea),
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IPaginate<Employee>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Employee>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.No.Contains(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.Department.Name.Contains(search.Name)),
                include: i => i.Include(x => x.Department).Include(x => x.Designation).Include(x => x.WorkLocation).Include(x => x.WorkType).Include(x => x.Team),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "No", ascending: !search.IsDescend);
        }
    }
